<template><div><el-card><div class="toolbar"><h2>导游管理</h2><el-input v-model="q.keyword" placeholder="关键字" style="width:200px"/><el-button type="primary" @click="load">查询</el-button><el-button type="success" @click="open({})">新增</el-button></div><el-table :data="list"><el-table-column prop="name" label="姓名"/><el-table-column prop="phone" label="手机"/><el-table-column prop="level" label="等级"/><el-table-column prop="status" label="状态"/><el-table-column label="操作" width="220"><template #default="{row}"><el-button link @click="open(row)">编辑</el-button><el-button link type="danger" @click="del(row.id)">删除</el-button></template></el-table-column></el-table></el-card><el-dialog v-model="show" title="导游管理"><el-form :model="form" label-width="100px"><el-form-item label="姓名"><el-input v-model="form.name"/></el-form-item><el-form-item label="手机"><el-input v-model="form.phone"/></el-form-item><el-form-item label="等级"><el-input v-model="form.level"/></el-form-item><el-form-item label="状态"><el-input v-model="form.status"/></el-form-item></el-form><template #footer><el-button @click="show=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue'; import { ElMessage,ElMessageBox } from 'element-plus'; import { guideApi } from '../../api/modules'; import StatusTag from '../../components/StatusTag.vue'; const q=reactive({page:1,size:20}),list=ref([]),show=ref(false),form=reactive({}); async function load(){const d=await guideApi.list(q); list.value=d.records||d} function open(row){Object.keys(form).forEach(k=>delete form[k]); Object.assign(form,row); show.value=true} async function save(){form.id?await guideApi.update(form.id,form):await guideApi.add(form); ElMessage.success('保存成功'); show.value=false; load()} async function del(id){await ElMessageBox.confirm('确认删除？'); await guideApi.del(id); load()} onMounted(load)</script>
